import org.springframework.boot.autoconfigure.security.oauth2.resource.OAuth2ResourceServerProperties;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.Customizer;
import org.springframework.security.config.annotation.method.configuration.EnableGlobalMethodSecurity;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.WebSecurityConfigurerAdapter;
import org.springframework.security.oauth2.jwt.JwtDecoder;
import org.springframework.security.oauth2.jwt.JwtDecoders;
import org.springframework.security.oauth2.server.resource.authentication.JwtAuthenticationConverter;

@Configuration
@EnableGlobalMethodSecurity(prePostEnabled = true)
public class WebSecurityConfig extends WebSecurityConfigurerAdapter {

    private final OAuth2ResourceServerProperties resourceServerProperties;

    public WebSecurityConfig(OAuth2ResourceServerProperties resourceServerProperties) {
        this.resourceServerProperties = resourceServerProperties;
    }

    @Override
    protected void configure(HttpSecurity http) throws Exception {
        http.cors(Customizer.withDefaults()).authorizeRequests((requests) ->
                requests.anyRequest().authenticated()
        ).oauth2ResourceServer().jwt().jwtAuthenticationConverter(jwtAuthenticationConverter());
    }

    @Bean
    public JwtDecoder jwtDecoder() {
        return JwtDecoders.fromIssuerLocation(resourceServerProperties.getJwt().getIssuerUri());
    }

    @Bean
    public JwtAuthenticationConverter jwtAuthenticationConverter() {
        JwtAuthenticationConverter converter = new JwtAuthenticationConverter();
        // Customize the JwtAuthenticationConverter if needed
        return converter;
    }
}
```

In this updated approach, the configuration class extends `WebSecurityConfigurerAdapter` and overrides the `configure(HttpSecurity http)` method to customize the security configuration.

The `JwtDecoder` bean is configured based on the `issuerUri` property from `OAuth2ResourceServerProperties`. And a `JwtAuthenticationConverter` bean is defined to provide additional customization if needed.

Make sure you have the necessary dependencies in your `pom.xml` file, including `spring-security-oauth2-autoconfigure` and `spring-security-oauth2-resource-server`.
Also, ensure that you have the appropriate properties configured in your application.yml or application.properties file, such as `spring.security.oauth2.resourceserver.jwt.issuer-uri` for the issuer URI.

This approach uses the `SecurityFilterChain` for handling security configurations, providing flexibility and control over the authentication and authorization processes.

