import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Configuration;
import org.springframework.http.HttpMethod;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.annotation.web.configuration.WebSecurityConfigurerAdapter;

@Configuration
@EnableWebSecurity
public class WebSecurityConfig extends WebSecurityConfigurerAdapter {

    @Value("${spring.security.oauth2.resourceserver.jwt.issuer-uri}")
    private String issuerUri;

    @Override
    protected void configure(HttpSecurity http) throws Exception {
        http
            .cors().and()
            .authorizeRequests()
                .antMatchers(HttpMethod.GET, "/api/public").permitAll() // Allow public access
                .anyRequest().authenticated() // Require authentication for other requests
            .and()
            .oauth2ResourceServer()
                .jwt()
                .issuerUri(issuerUri);
    }
}
```

In this approach, the `configure(HttpSecurity http)` method is overridden to define the security configuration. It allows public access to the `/api/public` endpoint with `permitAll()`, while requiring authentication for all other endpoints (`anyRequest().authenticated()`).

The `jwt().issuerUri(issuerUri)` configuration sets the issuer URI for JWT validation based on the `issuer-uri` property retrieved from the application properties file.

Make sure you have the necessary dependencies in your `pom.xml` file, including `spring-security-oauth2-autoconfigure` and `spring-security-oauth2-resource-server`.
Also, ensure that you have the appropriate properties configured in your application.yml or application.properties file, such as `spring.security.oauth2.resourceserver.jwt.issuer-uri` for the issuer URI.

This simpler approach uses the basic `WebSecurityConfigurerAdapter` without the need for additional customizations or bean configurations. It provides a straightforward way to configure authentication and authorization for the application.

